static int cmd_media_set_playing_order(const struct shell *sh, size_t argc, char *argv[])
{
	unsigned long order;
	int err = 0;

	order = shell_strtoul(argv[1], 0, &err);
	if (err != 0) {
		shell_error(sh, "Could not parse order: %d", err);

		return -ENOEXEC;
	}

	if (order > UINT8_MAX) {
		shell_error(sh, "Invalid order: %ld", order);

		return -ENOEXEC;
	}

